class Solution(object):
    def distinctEchoSubstrings(self, text):
        """
        :type text: str
        :rtype: int
        """
        n = len(text)
        seen = set()

        # Try all possible even-length substrings
        for i in range(n):
            for length in range(1, (n - i) // 2 + 1):
                # Substring [i, i+2*length-1]
                first_half = text[i:i+length]
                second_half = text[i+length:i+2*length]

                if first_half == second_half:
                    seen.add(first_half + second_half)

        return len(seen)
